form:Form.form:Scripts:
		function Datos()
{
	this.oi_personal_emp;
	this.oi_banco;
	this.disponible;
	this.contador;
	this.legajo;
} 

function NewClick()
{ 
	Ctrl('MAIN_GRID').AddNew();
	Ctrl("MAIN_GRID").SetCellXValue('oi_personal_emp',Ctrl('MAIN_GRID').GetSelectedRowIdx(),Ctrl("LIST").GetSelectAttrValue("id"));   
	Ctrl("MAIN_GRID").SetCellXValue('oi_banco_hora',Ctrl('MAIN_GRID').GetSelectedRowIdx(),Ctrl("LIST_BANCOS").GetSelectAttrValue("id"));  
	Ctrl("MAIN_GRID").SetCellXValue('n_cant_por_comp',Ctrl('MAIN_GRID').GetSelectedRowIdx(),Ctrl("LIST_BANCOS").GetSelectAttrValue("n_saldo"));
	if(VerificaRango(Ctrl('MAIN_GRID').GetCellXValue('oi_banco_hora',Ctrl('MAIN_GRID').GetSelectedRowIdx()))==0)     
		{       
			Ctrl('MAIN_GRID').GetCellControl('c_rango',Ctrl('MAIN_GRID').GetSelectedRowIdx()).SetXValue("");
			Ctrl('MAIN_GRID').GetCellControl('c_rango',Ctrl('MAIN_GRID').GetSelectedRowIdx()).SetEnabled(false);
		}
	else
		{
			Ctrl('MAIN_GRID').GetCellControl('c_rango',Ctrl('MAIN_GRID').GetSelectedRowIdx()).SetEnabled(true);
		}
}

function DellClick()
{ 
	Ctrl('MAIN_GRID').Del();
} 

function DellAllClick()
{ 
	Ctrl('MAIN_GRID').DelAllRows();
}  

function ListClick()
{
	Ctrl("oi_personal_emp").SetXValue(Ctrl("LIST").GetSelectAttrValue("id"));
	Ctrl('main').DoEvent("CargarLista");                  
}

function ListBancosClick()
{
	Ctrl("oi_banco_hora").SetXValue(Ctrl("LIST_BANCOS").GetSelectAttrValue("id")); 
}            

function OnLoad()
{ 
	ActualizaGrilla();
}           

function ValidarCampos()
{
	for(i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
	{	
		if(Ctrl('MAIN_GRID').GetCellControl('f_comp',i).GetXValue()=="")
		{
			alert("Debe completar la Fecha");
			Ctrl('MAIN_GRID').GetCellControl('f_comp',i).SetFocus();
			return false;	
		}

		if(Ctrl('MAIN_GRID').GetCellControl('c_rango',i).GetXValue()=="" && VerificaRango(Ctrl('MAIN_GRID').GetCellXValue('oi_banco_hora',i))==1)
		{
			alert("Debe completar el Tipo");
			Ctrl('MAIN_GRID').GetCellControl('c_rango',i).SetFocus();
			return false;	
		}

		if(Ctrl('MAIN_GRID').GetCellControl('n_cant_comp',i).GetXValue()=="")
		{
			alert("Debe completar la cantidad a solicitar");
			Ctrl('MAIN_GRID').GetCellControl('n_cant_comp',i).SetFocus();
			return false;	
		}   

		if(Ctrl('MAIN_GRID').GetCellControl('n_cant_comp',i).GetXValue()<=0)
		{
			alert("La cantidad a solicitar debe ser mayor a 0");
			Ctrl('MAIN_GRID').GetCellControl('n_cant_comp',i).SetFocus();
			return false;	
		}
	}   		             	
	return true;
}   

function ValidarCantidad()
{
	var arrPersonas = new Array();

	for(i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
	{ 
		var miDato = new Datos();   
		if (typeof (arrPersonas[parseInt(Ctrl('MAIN_GRID').GetCellXValue('oi_personal_emp',i))]) == "undefined")
			{
				miDato.disponible = Ctrl('MAIN_GRID').GetCellXValue('n_cant_por_comp',i);
				miDato.contador = Ctrl('MAIN_GRID').GetCellXValue('n_cant_comp',i); 
				miDato.oi_personal_emp = Ctrl('MAIN_GRID').GetCellXValue('oi_personal_emp',i);
				arrPersonas[parseInt(Ctrl('MAIN_GRID').GetCellXValue('oi_personal_emp',i))] = miDato;
			}
		else
			{
				miDato = arrPersonas[parseInt(Ctrl('MAIN_GRID').GetCellXValue('oi_personal_emp',i))]; 
				miDato.contador = parseInt(miDato.contador) + parseInt(Ctrl('MAIN_GRID').GetCellXValue('n_cant_comp',i)); 
				arrPersonas[parseInt(Ctrl('MAIN_GRID').GetCellXValue('oi_personal_emp',i))] = miDato;
			}   
	}

	for(var pers in arrPersonas)
	{
		var miDato2 = new Datos();
		miDato2 = arrPersonas[pers]; 
		if (parseInt(miDato2.contador) > parseInt(miDato2.disponible))
			{                
				for (var j=0; j<Ctrl("LIST").TotalRowsCount(); j++)
				{                                   
      				if (arrPersonas[pers].oi_personal_emp == Ctrl("LIST").GetAttrValue(j, 'id'))
					{	
						var legajo = Ctrl("LIST").GetAttrValue(j, 'legajo');													
						break;
					}
				}
				alert("Para el legajo '" + legajo + "' la cantidad total a solicitar no debe superar el saldo aprobado para el banco de horas");
				return false;				
			}
		else
		{  
			return true;                                 
		}	
	}
}

function Validar()
{
	if(ValidarCampos())
	{
		if(ValidarCantidad())
		{
			return true;
		} 
	}
} 

function ActualizaGrilla()
{           
	for(i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
		{           
			if(Ctrl('MAIN_GRID').GetCellXValue('oi_banco_hora',i)!='')
			{
				if(VerificaRango(Ctrl('MAIN_GRID').GetCellXValue('oi_banco_hora',i))==0)     
				{       
					Ctrl('MAIN_GRID').GetCellControl('c_rango',i).SetXValue("");
					Ctrl('MAIN_GRID').GetCellControl('c_rango',i).SetEnabled(false);
				}
				else
				{
					Ctrl('MAIN_GRID').GetCellControl('c_rango',i).SetEnabled(true);
				}
			}	 	
		}  
}

function VerificaRango(j)
{
	var param= new NomadXML("PARAM");    
	param.SetAttr("oi_banco_hora",j);                         

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	var result = nSQL.GetOBJ(Ctrl("main").getResource("QRY_BANCO"), param.ToString());

	return result.l_verifica_rango;
}            

function ValidarFecha(obj)
{   

//se tiene que reemplazar la seleccion de la persona, por el valor del oi del personal en la grilla

	if(VerificaRango(Ctrl('MAIN_GRID').GetCellXValue('oi_banco_hora',Ctrl('MAIN_GRID').GetSelectedRowIdx()))=="0")
	{
		var count=0;

		var oi_personal_emp = Ctrl('MAIN_GRID').GetCellXValue('oi_personal_emp',Ctrl('MAIN_GRID').GetSelectedRowIdx());

		for(i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
		{       
			if(Ctrl('MAIN_GRID').GetCellControl('oi_personal_emp',i).GetXValue()==oi_personal_emp && Ctrl('MAIN_GRID').GetCellControl('f_comp',i).GetXValue()==obj.GetXValue())
				count++;
		}

		if(count>1)
		{ 
			alert("No se puede repetir la Fecha de Compensación para el Legajo y el Banco de Horas seleccionado.");
			obj.SetXValue("");
			obj.SetFocus();
			return false;
		}
		else
		{
			var param= new NomadXML("PARAM");
			param.SetAttr("oi_personal_emp",oi_personal_emp);                         
	        param.SetAttr("f_comp",obj.GetXValue());

			var np = new NomadProxy("", ut);
			var nSQL = np.SQLService();
			var result = nSQL.GetOBJ(Ctrl("main").getResource("QRY_FECHA"), param.ToString());

			if(result.value==1)
			{
				alert("El legajo tiene compensaciones en la fecha ingresada y no puede cargar otra compensación en esa fecha para el Banco de Horas seleccionado.");
				obj.SetXValue("");
				obj.SetFocus();
				return false;
			}

		}

		return true;			
	}

	return true;
}
